// ===============================
// 1. Parse seguro do JSON do agente
// ===============================

let agentData = {};

try {
  const raw = ($json.output || "")
    .replace(/```json|```/g, "")
    .trim();

  agentData = JSON.parse(raw);
} catch (e) {
  agentData = {};
}

// ===============================
// 2. Campos do classificador
// ===============================

const categoria = agentData.categoria || "indefinido";
const score = agentData.score ?? "indefinido";
const sinais = (agentData.sinais_detectados || []).join(", ");
const justificativa = agentData.justificativa_curta || "—";

// ⚠️ Campo com espaço precisa de colchetes
const mensagemOriginal =
  agentData["Mensagem original da conversa"] || "(mensagem não disponível)";

// ===============================
// 3. Emoji por severidade
// ===============================

let emoji = "ℹ️";
if (categoria === "reclamacao") emoji = "⚠️";
if (categoria === "risco_de_churn") emoji = "🚨";
if (categoria === "cancelamento") emoji = "🛑";

// ===============================
// 4. Mensagem final formatada
// ===============================

const alertMessage = `
${emoji} *Alerta de conversa crítica*

*Categoria:* ${categoria}
*Score:* ${score}

*Sinais detectados:*
${sinais || "—"}

*Mensagem original:*
${mensagemOriginal}

*Análise:*
${justificativa}
`.trim();

// ===============================
// 5. Retorno
// ===============================

return [{
  ...$json,
  alert_message: alertMessage
}];

// ===============================
// 1. Captura segura dos dados do Telegram
// ===============================

const message = $json.message || {};

const chatType = message.chat?.type || "unknown";
const chatId = message.chat?.id ? String(message.chat.id) : "";
const groupTitle = message.chat?.title || "";

const text = message.text || "";

const userId = message.from?.id ? String(message.from.id) : "";
const userFirstName = message.from?.first_name || "";
const username = message.from?.username || "";

const isBot = message.from?.is_bot === true;

// ===============================
// 2. Validação da mensagem
// ===============================

// Só aceita mensagens de texto em grupos/supergrupos, vindas de humanos
const isValidMessage =
  (chatType === "group" || chatType === "supergroup") &&
  text.trim().length > 0 &&
  !isBot;

// ===============================
// 3. Retorno padronizado
// ===============================

return [{
  ...$json,

  // Contexto do chat
  chat_type: chatType,
  chat_id: chatId,
  group_title: groupTitle,

  // Autor da mensagem
  user_id: userId,
  user_name: userFirstName,
  username,

  // Conteúdo
  text,

  // Controle
  is_valid_message: isValidMessage
}];

// Grupos autorizados
const ALLOWED_GROUPS = [
  "{{ SEU_CHAT_ID_GRUPO_1 }}",
  "{{ SEU_CHAT_ID_GRUPO_2 }}"
];
// Captura segura
const chatId = String($json.message?.chat?.id || "");
const chatType = $json.message?.chat?.type || "unknown";

// Validação do grupo
const is_allowed_group =
  chatType === "private" || ALLOWED_GROUPS.includes(chatId);

// Define bloqueio
const blocked = !is_allowed_group;

return [
  {
    ...$json,
    chat_id: chatId,
    chat_type: chatType,
    is_allowed_group,
    blocked,
  }
];

// ============================
// 1. CONFIGURAÇÃO DO FILTRO
// ============================

// Termos que indicam risco de churn, reclamação ou tensão
const RISK_TERMS = [
  "cancelar",
  "cancelamento",
  "encerrar contrato",
  "quero sair",
  "vou sair",
  "não vou continuar",
  "insatisfeito",
  "muito insatisfeito",
  "reclamação",
  "problema recorrente",
  "isso não funciona",
  "péssimo atendimento",
  "estou frustrado",
  "não resolve",
  "cansei"
];

// Quantidade mínima de sinais para considerar suspeito
const MIN_HITS = 1;

// ============================
// 2. EXTRAÇÃO SEGURA DA MENSAGEM
// ============================

const rawText = $json.text || "";

// Normalização:
// - minúsculas
// - remove espaços duplicados
const text = rawText
  .toLowerCase()
  .replace(/\s+/g, " ")
  .trim();

// ============================
// 3. FILTRO BÁSICO
// ============================

// Se não houver texto real, ignora
if (!text || text.length < 3) {
  return [{
    ...$json,
    is_suspect: false,
    reason: "texto_vazio_ou_curto",
    risk_hits: 0
  }];
}

// ============================
// 4. DETECÇÃO DE PADRÕES (N-GRAMAS SIMPLES)
// ============================

// Verifica quais termos aparecem no texto
const matched_terms = RISK_TERMS.filter(term =>
  text.includes(term)
);

const risk_hits = matched_terms.length;

// ============================
// 5. DECISÃO FINAL (IA OU NÃO)
// ============================

// Mensagem é suspeita se:
// - possui pelo menos MIN_HITS termos de risco
const is_suspect = risk_hits >= MIN_HITS;

// ============================
// 6. RETORNO PADRONIZADO
// ============================

return [{
  ...$json,

  // Texto analisado
  normalized_text: text,

  // Resultado do filtro
  is_suspect,
  risk_hits,
  matched_terms,

  // Auditoria
  filter_version: "v1_keywords"
}];

// Lista de pessoas que devem receber o alerta
const RECIPIENTS = [
  { id: "{{ SEU_CHAT_ID_SIMONE }}", role: "Simone" },
  { id: "{{ SEU_CHAT_ID_MAYARA }}" , role: "Mayara" }
];

// Cria um item para cada destinatário
return RECIPIENTS.map(user => ({
  ...$json,
  chat_id: user.id,
  recipient_role: user.role
}));

// pegar dados do node anterior
let item = $json;

// corrigir quando o Edit Fields transforma message em texto
if (typeof item.message === "string") {
  try {
    item.message = JSON.parse(item.message);
  } catch (e) {
    item.message = {};
  }
}

const msg = item.message || {};

// detectar PDF real
const hasPdf =
  msg.document &&
  msg.document.mime_type === "application/pdf";

// imagem
const hasImage = !!item.imagem;

// vídeo / gif / vídeo como arquivo
const hasVideo =
  (msg.video && msg.video.file_id) ||
  (msg.animation && msg.animation.file_id) ||
  (msg.document &&
    msg.document.mime_type &&
    msg.document.mime_type.indexOf("video/") === 0);

// sticker
const hasSticker =
  msg.sticker && msg.sticker.file_id;

// texto
const hasText =
  typeof item.conversation === "string" && item.conversation.trim().length > 0;

// base64
const hasBase64 =
  typeof item.base64 === "string" && item.base64.length > 0;


// decidir tipo
let messageType = "unknown";

if (hasVideo) messageType = "video";
else if (hasSticker) messageType = "sticker";
else if (hasPdf) messageType = "pdf";
else if (hasImage) messageType = "image";
else if (hasBase64) messageType = "base64";
else if (hasText) messageType = "text";


// pegar file_id do vídeo
let videoFileId = null;

if (msg.video && msg.video.file_id) {
  videoFileId = msg.video.file_id;
} else if (msg.animation && msg.animation.file_id) {
  videoFileId = msg.animation.file_id;
} else if (
  msg.document &&
  msg.document.mime_type &&
  msg.document.mime_type.indexOf("video/") === 0
) {
  videoFileId = msg.document.file_id;
}


// saída
return {
  json: {
    ...item,
    telegramMeta: {
      messageType,
      pdfFileId: hasPdf ? msg.document.file_id : null,
      imageBase64: hasImage ? item.imagem : null,
      rawBase64: hasBase64 ? item.base64 : null,
      videoFileId: videoFileId,
      stickerEmoji: hasSticker ? msg.sticker.emoji : null,
      text: hasText ? item.conversation : null
    }
  }
};
